+const std = @import("std");
+const llama = @import("llama.zig");
+const simd = @import("simd_quant.zig");
+
+/// Attention Tracker for Dynamic Token Pruning
+///
+/// Tracks token importance based on attention patterns and entropy heuristics.
+/// Allows pruning low-importance tokens to reduce KV cache memory usage.
+///
+/// Reference: "H2O: Heavy-Hitter Oracle for Efficient Generative Inference"
+/// (Zhang et al., 2023)
+
+pub const AttentionTracker = struct {
+    allocator: std.mem.Allocator,
+
+    /// Token importance scores (position -> cumulative score)
+    importance: std.AutoHashMap(u32, f32),
+
+    /// Attention count per position (for averaging)
+    attention_count: std.AutoHashMap(u32, u32),
+
+    /// Configuration
+    decay_rate: f32, // Decay factor for old scores (default 0.95)
+    prune_threshold: f32, // Minimum importance to keep (default 0.01)
+    min_tokens_kept: u32, // Minimum tokens to always keep (default 64)
+    prune_interval: u32, // Prune every N tokens (default 64)
+
+    /// Statistics
+    tokens_tracked: u64,
+    tokens_pruned: u64,
+    last_prune_pos: u32,
+
+    const Self = @This();
+
+    /// Initialize attention tracker with default settings
+    pub fn init(allocator: std.mem.Allocator) Self {
+        return Self{
+            .allocator = allocator,
+            .importance = std.AutoHashMap(u32, f32).init(allocator),
+            .attention_count = std.AutoHashMap(u32, u32).init(allocator),
+            .decay_rate = 0.95,
+            .prune_threshold = 0.01,
+            .min_tokens_kept = 64,
+            .prune_interval = 64,
+            .tokens_tracked = 0,
+            .tokens_pruned = 0,
+            .last_prune_pos = 0,
+        };
+    }
+
+    /// Initialize with custom settings
+    pub fn initWithConfig(
+        allocator: std.mem.Allocator,
+        decay_rate: f32,
+        prune_threshold: f32,
+        min_tokens_kept: u32,
+        prune_interval: u32,
+    ) Self {
+        return Self{
+            .allocator = allocator,
+            .importance = std.AutoHashMap(u32, f32).init(allocator),
+            .attention_count = std.AutoHashMap(u32, u32).init(allocator),
+            .decay_rate = decay_rate,
+            .prune_threshold = prune_threshold,
+            .min_tokens_kept = min_tokens_kept,
+            .prune_interval = prune_interval,
+            .tokens_tracked = 0,
+            .tokens_pruned = 0,
+            .last_prune_pos = 0,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.importance.deinit();
+        self.attention_count.deinit();
+    }
+
+    /// Update importance scores based on logits distribution
+    /// Uses entropy as a proxy for attention - low entropy = focused attention
+    pub fn updateFromLogits(
+        self: *Self,
+        logits: []const f32,
+        current_pos: u32,
+        context_positions: []const u32,
+    ) !void {
+        // Compute softmax probabilities
+        var probs = try self.allocator.alloc(f32, logits.len);
+        defer self.allocator.free(probs);
+        @memcpy(probs, logits);
+
+        // Use SIMD softmax if available
+        _ = simd.simdSoftmax(probs);
+
+        // Compute entropy (using SIMD)
+        const entropy = simd.simdEntropy(probs);
+
+        // Higher entropy = more uniform distribution = less focused attention
+        // Lower entropy = peaked distribution = focused on specific tokens
+        // We want to reward tokens that lead to low-entropy (confident) predictions
+
+        // Importance boost for tokens leading to confident predictions
+        const confidence = 1.0 / (1.0 + entropy);
+
+        // Apply decay to existing scores
+        var iter = self.importance.iterator();
+        while (iter.next()) |entry| {
+            entry.value_ptr.* *= self.decay_rate;
+        }
+
+        // Update importance for context positions
+        // Weight by recency (more recent = more important initially)
+        for (context_positions, 0..) |pos, idx| {
+            const recency_weight = @as(f32, @floatFromInt(idx + 1)) / @as(f32, @floatFromInt(context_positions.len));
+            const score_delta = confidence * recency_weight;
+
+            if (self.importance.getPtr(pos)) |score| {
+                score.* += score_delta;
+            } else {
+                try self.importance.put(pos, score_delta);
+            }
+
+            // Track attention count
+            if (self.attention_count.getPtr(pos)) |count| {
+                count.* += 1;
+            } else {
+                try self.attention_count.put(pos, 1);
+            }
+        }
+
+        self.tokens_tracked += 1;
+    }
+
+    /// Simple update without logits - just track position usage
+    pub fn trackPosition(self: *Self, pos: u32) !void {
+        if (self.importance.getPtr(pos)) |score| {
+            score.* += 1.0;
+        } else {
+            try self.importance.put(pos, 1.0);
+        }
+
+        if (self.attention_count.getPtr(pos)) |count| {
+            count.* += 1;
+        } else {
+            try self.attention_count.put(pos, 1);
+        }
+
+        self.tokens_tracked += 1;
+    }
+
+    /// Get candidates for pruning (positions with lowest importance)
+    /// Returns up to `max_count` positions sorted by importance (ascending)
+    pub fn getPruneCandidates(
+        self: *Self,
+        max_count: u32,
+        protect_range: u32, // Don't prune positions < this (e.g., sink tokens)
+    ) ![]u32 {
+        var candidates = std.ArrayList(PruneCandidate).init(self.allocator);
+        defer candidates.deinit();
+
+        // Collect all positions with their normalized importance
+        var iter = self.importance.iterator();
+        while (iter.next()) |entry| {
+            const pos = entry.key_ptr.*;
+
+            // Skip protected positions (sink tokens, etc.)
+            if (pos < protect_range) continue;
+
+            // Normalize by attention count to get average importance
+            const count = self.attention_count.get(pos) orelse 1;
+            const avg_importance = entry.value_ptr.* / @as(f32, @floatFromInt(@max(count, 1)));
+
+            if (avg_importance < self.prune_threshold) {
+                try candidates.append(.{
+                    .position = pos,
+                    .importance = avg_importance,
+                });
+            }
+        }
+
+        // Sort by importance (ascending - lowest first)
+        std.mem.sort(PruneCandidate, candidates.items, {}, struct {
+            fn lessThan(_: void, a: PruneCandidate, b: PruneCandidate) bool {
+                return a.importance < b.importance;
+            }
+        }.lessThan);
+
+        // Return up to max_count positions
+        const result_count = @min(max_count, @as(u32, @intCast(candidates.items.len)));
+        var result = try self.allocator.alloc(u32, result_count);
+
+        for (0..result_count) |i| {
+            result[i] = candidates.items[i].position;
+        }
+
+        return result;
+    }
+
+    const PruneCandidate = struct {
+        position: u32,
+        importance: f32,
+    };
+
+    /// Prune tokens from KV cache
+    /// Returns number of tokens actually pruned
+    pub fn pruneTokens(
+        self: *Self,
+        ctx: *llama.c.llama_context,
+        seq_id: i32,
+        max_prune: u32,
+        protect_range: u32,
+    ) !u32 {
+        const candidates = try self.getPruneCandidates(max_prune, protect_range);
+        defer self.allocator.free(candidates);
+
+        // Ensure we keep minimum tokens
+        const current_count = self.importance.count();
+        if (current_count <= self.min_tokens_kept) {
+            return 0;
+        }
+
+        const max_allowed_prune = current_count - self.min_tokens_kept;
+        const actual_prune = @min(@as(u32, @intCast(candidates.len)), @as(u32, @intCast(max_allowed_prune)));
+
+        // Remove each candidate from KV cache
+        for (candidates[0..actual_prune]) |pos| {
+            // Remove single token at position
+            llama.c.llama_kv_cache_seq_rm(
+                ctx,
+                seq_id,
+                @intCast(pos),
+                @intCast(pos + 1),
+            );
+
+            // Remove from tracking
+            _ = self.importance.remove(pos);
+            _ = self.attention_count.remove(pos);
+        }
+
+        self.tokens_pruned += actual_prune;
+        return actual_prune;
+    }
+
+    /// Check if pruning should be triggered
+    pub fn shouldPrune(self: *const Self, current_pos: u32) bool {
+        return current_pos >= self.last_prune_pos + self.prune_interval;
+    }
+
+    /// Mark that pruning was performed
+    pub fn markPruned(self: *Self, current_pos: u32) void {
+        self.last_prune_pos = current_pos;
+    }
+
+    /// Get importance score for a position
+    pub fn getImportance(self: *const Self, pos: u32) f32 {
+        return self.importance.get(pos) orelse 0.0;
+    }
+
+    /// Get normalized importance (importance / attention_count)
+    pub fn getNormalizedImportance(self: *const Self, pos: u32) f32 {
+        const raw = self.importance.get(pos) orelse return 0.0;
+        const count = self.attention_count.get(pos) orelse 1;
+        return raw / @as(f32, @floatFromInt(@max(count, 1)));
+    }
+
+    /// Reset all tracking data
+    pub fn reset(self: *Self) void {
+        self.importance.clearRetainingCapacity();
+        self.attention_count.clearRetainingCapacity();
+        self.tokens_tracked = 0;
+        self.tokens_pruned = 0;
+        self.last_prune_pos = 0;
+    }
+
+    /// Get statistics
+    pub fn getStats(self: *const Self) struct {
+        tracked_positions: usize,
+        tokens_tracked: u64,
+        tokens_pruned: u64,
+        prune_rate: f32,
+        avg_importance: f32,
+    } {
+        var total_importance: f32 = 0.0;
+        var iter = self.importance.iterator();
+        while (iter.next()) |entry| {
+            total_importance += entry.value_ptr.*;
+        }
+
+        const count = self.importance.count();
+        const avg = if (count > 0) total_importance / @as(f32, @floatFromInt(count)) else 0.0;
+
+        return .{
+            .tracked_positions = count,
+            .tokens_tracked = self.tokens_tracked,
+            .tokens_pruned = self.tokens_pruned,
+            .prune_rate = if (self.tokens_tracked > 0)
+                @as(f32, @floatFromInt(self.tokens_pruned)) / @as(f32, @floatFromInt(self.tokens_tracked))
+            else
+                0.0,
+            .avg_importance = avg,
+        };
+    }
+
+    /// Batch update for multiple positions with weights
+    pub fn batchUpdate(
+        self: *Self,
+        positions: []const u32,
+        weights: []const f32,
+    ) !void {
+        std.debug.assert(positions.len == weights.len);
+
+        // Apply decay first
+        var iter = self.importance.iterator();
+        while (iter.next()) |entry| {
+            entry.value_ptr.* *= self.decay_rate;
+        }
+
+        // Update with new weights
+        for (positions, weights) |pos, weight| {
+            if (self.importance.getPtr(pos)) |score| {
+                score.* += weight;
+            } else {
+                try self.importance.put(pos, weight);
+            }
+
+            if (self.attention_count.getPtr(pos)) |count| {
+                count.* += 1;
+            } else {
+                try self.attention_count.put(pos, 1);
+            }
+        }
+
+        self.tokens_tracked += positions.len;
+    }
+};
+
+/// Heavy-Hitter Oracle (H2O) style pruning policy
+/// Keeps tokens that are frequently attended to across multiple layers
+pub const H2OPolicy = struct {
+    allocator: std.mem.Allocator,
+
+    /// Per-layer attention accumulators
+    layer_scores: std.ArrayList(std.AutoHashMap(u32, f32)),
+
+    /// Number of layers
+    num_layers: u32,
+
+    /// Heavy-hitter threshold (top-k percent to keep)
+    heavy_hitter_percent: f32,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, num_layers: u32) !Self {
+        var layer_scores = std.ArrayList(std.AutoHashMap(u32, f32)).init(allocator);
+        errdefer {
+            for (layer_scores.items) |*map| {
+                map.deinit();
+            }
+            layer_scores.deinit();
+        }
+
+        for (0..num_layers) |_| {
+            try layer_scores.append(std.AutoHashMap(u32, f32).init(allocator));
+        }
+
+        return Self{
+            .allocator = allocator,
+            .layer_scores = layer_scores,
+            .num_layers = num_layers,
+            .heavy_hitter_percent = 0.2, // Keep top 20% as heavy hitters
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        for (self.layer_scores.items) |*map| {
+            map.deinit();
+        }
+        self.layer_scores.deinit();
+    }
+
+    /// Update attention scores for a specific layer
+    pub fn updateLayer(
+        self: *Self,
+        layer_idx: u32,
+        positions: []const u32,
+        scores: []const f32,
+    ) !void {
+        if (layer_idx >= self.num_layers) return;
+
+        var map = &self.layer_scores.items[layer_idx];
+        for (positions, scores) |pos, score| {
+            if (map.getPtr(pos)) |existing| {
+                existing.* += score;
+            } else {
+                try map.put(pos, score);
+            }
+        }
+    }
+
+    /// Get heavy hitters (tokens with high attention across all layers)
+    pub fn getHeavyHitters(self: *Self, max_count: u32) ![]u32 {
+        var combined = std.AutoHashMap(u32, f32).init(self.allocator);
+        defer combined.deinit();
+
+        // Sum scores across all layers
+        for (self.layer_scores.items) |*layer_map| {
+            var iter = layer_map.iterator();
+            while (iter.next()) |entry| {
+                if (combined.getPtr(entry.key_ptr.*)) |score| {
+                    score.* += entry.value_ptr.*;
+                } else {
+                    try combined.put(entry.key_ptr.*, entry.value_ptr.*);
+                }
+            }
+        }
+
+        // Sort by score (descending)
+        var candidates = std.ArrayList(struct { pos: u32, score: f32 }).init(self.allocator);
+        defer candidates.deinit();
+
+        var iter = combined.iterator();
+        while (iter.next()) |entry| {
+            try candidates.append(.{ .pos = entry.key_ptr.*, .score = entry.value_ptr.* });
+        }
+
+        std.mem.sort(@TypeOf(candidates.items[0]), candidates.items, {}, struct {
+            fn cmp(_: void, a: @TypeOf(candidates.items[0]), b: @TypeOf(candidates.items[0])) bool {
+                return a.score > b.score; // Descending
+            }
+        }.cmp);
+
+        // Return top heavy hitters
+        const result_count = @min(max_count, @as(u32, @intCast(candidates.items.len)));
+        var result = try self.allocator.alloc(u32, result_count);
+
+        for (0..result_count) |i| {
+            result[i] = candidates.items[i].pos;
+        }
+
+        return result;
+    }
+
+    /// Reset all layer scores
+    pub fn reset(self: *Self) void {
+        for (self.layer_scores.items) |*map| {
+            map.clearRetainingCapacity();
+        }
+    }
+};
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "attention tracker basic operations" {
+    const allocator = std.testing.allocator;
+
+    var tracker = AttentionTracker.init(allocator);
+    defer tracker.deinit();
+
+    // Track some positions
+    try tracker.trackPosition(0);
+    try tracker.trackPosition(1);
+    try tracker.trackPosition(2);
+    try tracker.trackPosition(0); // Double track position 0
+
+    // Position 0 should have higher importance
+    const imp0 = tracker.getImportance(0);
+    const imp1 = tracker.getImportance(1);
+    try std.testing.expect(imp0 > imp1);
+
+    // Stats should reflect tracking
+    const stats = tracker.getStats();
+    try std.testing.expectEqual(@as(usize, 3), stats.tracked_positions);
+    try std.testing.expectEqual(@as(u64, 4), stats.tokens_tracked);
+}
+
+test "attention tracker prune candidates" {
+    const allocator = std.testing.allocator;
+
+    var tracker = AttentionTracker.initWithConfig(
+        allocator,
+        0.95, // decay
+        0.5, // prune threshold
+        2, // min tokens
+        64, // prune interval
+    );
+    defer tracker.deinit();
+
+    // Add positions with varying importance
+    try tracker.importance.put(0, 10.0); // High importance
+    try tracker.importance.put(1, 0.1); // Low importance
+    try tracker.importance.put(2, 0.2); // Low importance
+    try tracker.importance.put(3, 5.0); // Medium importance
+
+    try tracker.attention_count.put(0, 1);
+    try tracker.attention_count.put(1, 1);
+    try tracker.attention_count.put(2, 1);
+    try tracker.attention_count.put(3, 1);
+
+    // Get prune candidates (should be positions 1 and 2)
+    const candidates = try tracker.getPruneCandidates(10, 0);
+    defer allocator.free(candidates);
+
+    try std.testing.expect(candidates.len >= 2);
+    // Lowest importance should be first
+    try std.testing.expectEqual(@as(u32, 1), candidates[0]);
+}
+
+test "batch update" {
+    const allocator = std.testing.allocator;
+
+    var tracker = AttentionTracker.init(allocator);
+    defer tracker.deinit();
+
+    const positions = [_]u32{ 0, 1, 2 };
+    const weights = [_]f32{ 1.0, 2.0, 3.0 };
+
+    try tracker.batchUpdate(&positions, &weights);
+
+    try std.testing.expectApproxEqAbs(@as(f32, 1.0), tracker.getImportance(0), 0.01);
+    try std.testing.expectApproxEqAbs(@as(f32, 2.0), tracker.getImportance(1), 0.01);
+    try std.testing.expectApproxEqAbs(@as(f32, 3.0), tracker.getImportance(2), 0.01);
+}

