+
+    // =========================================================================
+    // Optimization 2: Async Weight Fusion
+    // =========================================================================
+
+    /// Spawn background process to merge LoRA weights into base model
+    /// This eliminates adapter overhead during inference (y = Wx instead of y = Wx + BAx)
+    pub fn spawnWeightFusion(self: *Hippocampus, lora_path: []const u8) !void {
+        // Don't spawn if fusion already in progress
+        if (self.fusion_in_progress.load(.monotonic)) {
+            logger.debug("Weight fusion already in progress, skipping", .{});
+            return;
+        }
+
+        self.fusion_in_progress.store(true, .monotonic);
+
+        // Determine output path for fused model
+        const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+        const output_path = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/.cache/zell/fused/{s}_fused.gguf",
+            .{ home, self.adapter_name },
+        );
+        errdefer self.allocator.free(output_path);
+
+        // Ensure directory exists
+        const dir_path = std.fs.path.dirname(output_path) orelse return error.InvalidPath;
+        try std.fs.cwd().makePath(dir_path);
+
+        // Spawn background fusion thread
+        const fusion_thread = try std.Thread.spawn(.{}, weightFusionWorker, .{
+            self,
+            lora_path,
+            output_path,
+        });
+        fusion_thread.detach(); // Run independently
+
+        logger.info("Spawned async weight fusion: {s} -> {s}", .{ lora_path, output_path });
+    }
+
+    /// Background worker for weight fusion
+    fn weightFusionWorker(
+        self: *Hippocampus,
+        lora_path: []const u8,
+        output_path: []const u8,
+    ) void {
+        defer self.fusion_in_progress.store(false, .monotonic);
+
+        // Try to find llama-export-lora tool
+        const tools = [_][]const u8{
+            "llama-export-lora",
+            "./llama-export-lora",
+            "vendor/llama.cpp/build/bin/llama-export-lora",
+        };
+
+        var found_tool: ?[]const u8 = null;
+        for (tools) |tool| {
+            if (std.fs.cwd().access(tool, .{})) {
+                found_tool = tool;
+                break;
+            } else |_| {
+                // Try in PATH
+                const result = std.process.Child.run(.{
+                    .allocator = self.allocator,
+                    .argv = &[_][]const u8{ "which", tool },
+                }) catch continue;
+                defer self.allocator.free(result.stdout);
+                defer self.allocator.free(result.stderr);
+
+                if (result.term.Exited == 0 and result.stdout.len > 0) {
+                    found_tool = tool;
+                    break;
+                }
+            }
+        }
+
+        if (found_tool == null) {
+            logger.warn("llama-export-lora not found, skipping weight fusion", .{});
+            return;
+        }
+
+        logger.info("Starting weight fusion with {s}...", .{found_tool.?});
+
+        // Run export-lora
+        const argv = [_][]const u8{
+            found_tool.?,
+            "-m",
+            self.model_path,
+            "-o",
+            output_path,
+            "--lora",
+            lora_path,
+        };
+
+        var child = std.process.Child.init(&argv, self.allocator);
+        child.spawn() catch |err| {
+            logger.err("Failed to spawn weight fusion: {}", .{err});
+            return;
+        };
+
+        const result = child.wait() catch |err| {
+            logger.err("Weight fusion process failed: {}", .{err});
+            return;
+        };
+
+        if (result.Exited == 0) {
+            // Success! Update fused model path
+            if (self.fused_model_path) |old_path| {
+                self.allocator.free(old_path);
+            }
+            self.fused_model_path = self.allocator.dupe(u8, output_path) catch null;
+
+            logger.info("Weight fusion complete: {s}", .{output_path});
+            logger.info("Next inference can use fused model (zero adapter overhead)", .{});
+        } else {
+            logger.warn("Weight fusion exited with code {}", .{result.Exited});
+        }
+    }
+
+    /// Get path to fused model if available
+    pub fn getFusedModelPath(self: *const Hippocampus) ?[]const u8 {
+        return self.fused_model_path;
+    }
+
+    /// Check if fused model is ready for use
+    pub fn isFusedModelReady(self: *const Hippocampus) bool {
