+const std = @import("std");
+const llama = @import("llama.zig");
+const c = llama.c;
+const logger = @import("logger.zig");
+
+/// KV Ring Buffer implementing "Attention Sinks" pattern from StreamingLLM paper
+///
+/// Keeps first N tokens as "sinks" (attention anchors) plus a rolling window
+/// of recent tokens. This enables infinite conversation with O(1) memory.
+///
+/// Memory Layout:
+/// [SINK_0][SINK_1][SINK_2][SINK_3][WINDOW_0][WINDOW_1]...[WINDOW_N]
+///  ^--- Never evicted ---^        ^--- Rolling window, FIFO eviction ---^
+pub const KVRingBuffer = struct {
+    allocator: std.mem.Allocator,
+
+    // Configuration
+    sink_tokens: u32, // Number of tokens to always keep (attention sinks)
+    window_size: u32, // Size of rolling window
+
+    // State
+    total_tokens_processed: u64, // Total tokens ever processed
+    current_size: u32, // Current number of tokens in buffer
+    window_start: u32, // Logical start of window (for ring buffer)
+
+    // Per-sequence tracking
+    seq_states: std.AutoHashMap(i32, SeqState),
+
+    const Self = @This();
+
+    /// State for a single sequence
+    pub const SeqState = struct {
+        tokens_processed: u64,
+        current_size: u32,
+        is_full: bool, // Has the ring buffer wrapped?
+    };
+
+    /// Initialize KV ring buffer
+    /// sink_count: Number of initial tokens to preserve (default 4)
+    /// window: Size of rolling window (default 2048)
+    pub fn init(
+        allocator: std.mem.Allocator,
+        sink_count: u32,
+        window: u32,
+    ) Self {
+        return Self{
+            .allocator = allocator,
+            .sink_tokens = sink_count,
+            .window_size = window,
+            .total_tokens_processed = 0,
+            .current_size = 0,
+            .window_start = sink_count, // Window starts after sinks
+            .seq_states = std.AutoHashMap(i32, SeqState).init(allocator),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.seq_states.deinit();
+    }
+
+    /// Get effective context size (sinks + window)
+    pub fn getEffectiveContextSize(self: *const Self) u32 {
+        return self.sink_tokens + self.window_size;
+    }
+
+    /// Check if a position is within the sink region
+    pub fn isSinkPosition(self: *const Self, pos: u32) bool {
+        return pos < self.sink_tokens;
+    }
+
+    /// Push a new token, potentially evicting old ones
+    /// Returns the position where the token should be placed
+    pub fn push(
+        self: *Self,
+        ctx: *c.llama_context,
+        seq_id: i32,
+        token_pos: u32,
+    ) !u32 {
+        const effective_size = self.getEffectiveContextSize();
+
+        // If we haven't filled the buffer yet, just append
+        if (token_pos < effective_size) {
+            self.current_size = token_pos + 1;
+            self.total_tokens_processed += 1;
+            return token_pos;
+        }
+
+        // Buffer is full - need to evict oldest non-sink token
+        // This is the "rotate" operation
+
+        // 1. Remove the oldest token in the window (position = sink_tokens)
+        const evict_pos = self.sink_tokens;
+        c.llama_kv_cache_seq_rm(ctx, seq_id, @intCast(evict_pos), @intCast(evict_pos + 1));
+
+        // 2. Shift all positions down by 1 (tokens after evict_pos)
+        // This moves [sink_tokens+1, effective_size) to [sink_tokens, effective_size-1)
+        c.llama_kv_cache_seq_add(
+            ctx,
+            seq_id,
+            @intCast(evict_pos + 1), // Start position
+            -1, // End position (-1 = end of sequence)
+            -1, // Delta (shift left by 1)
+        );
+
+        self.total_tokens_processed += 1;
+
+        // New token goes at the end of the effective context
+        return effective_size - 1;
+    }
+
+    /// Get the actual position for a logical position
+    /// This handles the ring buffer wrapping
+    pub fn getActualPosition(self: *const Self, logical_pos: u64) u32 {
+        const effective_size = self.getEffectiveContextSize();
+
+        if (logical_pos < self.sink_tokens) {
+            // Sink region - direct mapping
+            return @intCast(logical_pos);
+        }
+
+        if (logical_pos < effective_size) {
+            // Buffer not full yet - direct mapping
+            return @intCast(logical_pos);
+        }
+
+        // Buffer is full - compute wrapped position
+        // Position in window = (logical_pos - sink_tokens) % window_size
+        const window_offset = (logical_pos - self.sink_tokens) % self.window_size;
+        return self.sink_tokens + @as(u32, @intCast(window_offset));
+    }
+
+    /// Get the current effective length (for position tracking)
+    pub fn getEffectiveLength(self: *const Self) u32 {
+        return @min(self.current_size, self.getEffectiveContextSize());
+    }
+
+    /// Check if the buffer is full (wrapped at least once)
+    pub fn isFull(self: *const Self) bool {
+        return self.total_tokens_processed >= self.getEffectiveContextSize();
+    }
+
+    /// Reset the ring buffer for a sequence
+    pub fn reset(self: *Self, ctx: *c.llama_context, seq_id: i32) void {
+        // Clear all KV cache for this sequence
+        c.llama_kv_cache_seq_rm(ctx, seq_id, 0, -1);
+
+        self.total_tokens_processed = 0;
+        self.current_size = 0;
+        self.window_start = self.sink_tokens;
+
+        _ = self.seq_states.remove(seq_id);
+    }
+
+    /// Get statistics about the ring buffer
+    pub fn getStats(self: *const Self) struct {
+        sink_tokens: u32,
+        window_size: u32,
+        effective_size: u32,
+        tokens_processed: u64,
+        current_size: u32,
+        is_full: bool,
+        evictions: u64,
+    } {
+        const effective = self.getEffectiveContextSize();
+        return .{
+            .sink_tokens = self.sink_tokens,
+            .window_size = self.window_size,
+            .effective_size = effective,
+            .tokens_processed = self.total_tokens_processed,
+            .current_size = self.current_size,
+            .is_full = self.isFull(),
+            .evictions = if (self.total_tokens_processed > effective)
+                self.total_tokens_processed - effective
+            else
+                0,
+        };
+    }
+};
+
+/// Manager for multiple ring buffers (one per cell/sequence)
+pub const RingBufferManager = struct {
+    allocator: std.mem.Allocator,
+    buffers: std.AutoHashMap(i32, KVRingBuffer),
+    default_sink_tokens: u32,
+    default_window_size: u32,
+
+    const Self = @This();
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        sink_tokens: u32,
+        window_size: u32,
+    ) Self {
+        return Self{
+            .allocator = allocator,
+            .buffers = std.AutoHashMap(i32, KVRingBuffer).init(allocator),
+            .default_sink_tokens = sink_tokens,
+            .default_window_size = window_size,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        var iter = self.buffers.iterator();
+        while (iter.next()) |entry| {
+            entry.value_ptr.deinit();
+        }
+        self.buffers.deinit();
+    }
+
+    /// Get or create ring buffer for a sequence
+    pub fn getOrCreate(self: *Self, seq_id: i32) !*KVRingBuffer {
+        const result = try self.buffers.getOrPut(seq_id);
+        if (!result.found_existing) {
+            result.value_ptr.* = KVRingBuffer.init(
+                self.allocator,
+                self.default_sink_tokens,
+                self.default_window_size,
+            );
+        }
+        return result.value_ptr;
+    }
+
+    /// Get ring buffer if it exists
+    pub fn get(self: *Self, seq_id: i32) ?*KVRingBuffer {
+        return self.buffers.getPtr(seq_id);
+    }
+
+    /// Remove ring buffer for a sequence
+    pub fn remove(self: *Self, seq_id: i32) void {
+        if (self.buffers.fetchRemove(seq_id)) |kv| {
+            var buf = kv.value;
+            buf.deinit();
+        }
+    }
+
+    /// Get total statistics across all buffers
+    pub fn getTotalStats(self: *Self) struct {
+        buffer_count: usize,
+        total_tokens_processed: u64,
+        total_evictions: u64,
+    } {
+        var total_processed: u64 = 0;
+        var total_evictions: u64 = 0;
+
+        var iter = self.buffers.iterator();
+        while (iter.next()) |entry| {
+            const stats = entry.value_ptr.getStats();
+            total_processed += stats.tokens_processed;
+            total_evictions += stats.evictions;
+        }
+
+        return .{
+            .buffer_count = self.buffers.count(),
+            .total_tokens_processed = total_processed,
+            .total_evictions = total_evictions,
+        };
+    }
+};
+
+// Tests
+test "kv ring buffer basic operations" {
+    const allocator = std.testing.allocator;
+
+    var buffer = KVRingBuffer.init(allocator, 4, 8); // 4 sinks + 8 window = 12 total
+    defer buffer.deinit();
+
+    // Effective size should be 12
+    try std.testing.expectEqual(@as(u32, 12), buffer.getEffectiveContextSize());
+
+    // Initially not full
+    try std.testing.expect(!buffer.isFull());
+
+    // Sink positions
+    try std.testing.expect(buffer.isSinkPosition(0));
+    try std.testing.expect(buffer.isSinkPosition(3));
+    try std.testing.expect(!buffer.isSinkPosition(4));
+}
+
+test "ring buffer manager" {
+    const allocator = std.testing.allocator;
+
+    var manager = RingBufferManager.init(allocator, 4, 2048);
+    defer manager.deinit();
+
+    // Create buffer for sequence 0
+    const buf0 = try manager.getOrCreate(0);
+    try std.testing.expectEqual(@as(u32, 4), buf0.sink_tokens);
+
+    // Should get same buffer when requested again
+    const buf0_again = try manager.getOrCreate(0);
+    try std.testing.expectEqual(buf0, buf0_again);
+
+    // Different sequence gets different buffer
+    const buf1 = try manager.getOrCreate(1);
+    try std.testing.expect(buf0 != buf1);
+}

