+    // Optimization 2: Cached Adapter Application
+    // =========================================================================
+
+    /// Apply adapter with caching - skips if already applied
+    /// Returns true if adapter was applied, false if already active
+    pub fn applyAdapterOptimized(
+        self: *Self,
+        ctx: *llama.Context,
+        id: []const u8,
+        scale: f32,
