+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        // Check if already applied
+        if (self.current_adapter_id) |current_id| {
+            if (std.mem.eql(u8, current_id, id)) {
+                logger.debug("Adapter '{s}' already applied, skipping", .{id});
+                return false; // Already applied
+            }
