+const std = @import("std");
+const llama = @import("llama.zig");
+const c = llama.c;
+const logger = @import("logger.zig");
+
+/// Token type alias
+pub const Token = c.llama_token;
+
+/// Token distribution for a given n-gram context
+pub const TokenDistribution = struct {
+    /// Most likely next token
+    top_token: Token,
+    /// Frequency count for the top token
+    count: u32,
+    /// Total observations of this n-gram
+    total_count: u32,
+    /// Last time this n-gram was observed
+    last_seen: i64,
+
+    pub fn probability(self: *const TokenDistribution) f32 {
+        if (self.total_count == 0) return 0.0;
+        return @as(f32, @floatFromInt(self.count)) / @as(f32, @floatFromInt(self.total_count));
+    }
+};
+
+/// N-gram cache for "Echo" speculative decoding
+/// Uses conversation history as a lightweight draft model
+pub const NGramCache = struct {
+    allocator: std.mem.Allocator,
+
+    /// Trigram cache: hash(token[i-2], token[i-1]) -> distribution of token[i]
+    trigrams: std.AutoHashMap(u64, TokenDistribution),
+
+    /// Bigram cache for fallback: hash(token[i-1]) -> distribution of token[i]
+    bigrams: std.AutoHashMap(u64, TokenDistribution),
+
+    /// Statistics
+    total_trigrams: usize,
+    total_bigrams: usize,
+    cache_hits: usize,
+    cache_misses: usize,
+
+    /// Configuration
+    min_confidence: f32, // Minimum probability to use prediction
+    max_draft_tokens: u32, // Maximum tokens to draft at once
+    decay_factor: f32, // How much to decay old counts
+
+    const Self = @This();
+
+    /// Initialize empty n-gram cache
+    pub fn init(allocator: std.mem.Allocator) Self {
+        return Self{
+            .allocator = allocator,
+            .trigrams = std.AutoHashMap(u64, TokenDistribution).init(allocator),
+            .bigrams = std.AutoHashMap(u64, TokenDistribution).init(allocator),
+            .total_trigrams = 0,
+            .total_bigrams = 0,
+            .cache_hits = 0,
+            .cache_misses = 0,
+            .min_confidence = 0.3, // Only use predictions with >30% confidence
+            .max_draft_tokens = 8, // Draft up to 8 tokens at once
+            .decay_factor = 0.99, // Slight decay for older patterns
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.trigrams.deinit();
+        self.bigrams.deinit();
+    }
+
+    /// Hash two tokens to create trigram key
+    fn hashTrigram(t1: Token, t2: Token) u64 {
+        const bytes = [_]u8{
+            @truncate(@as(u32, @bitCast(t1)) >> 0),
+            @truncate(@as(u32, @bitCast(t1)) >> 8),
+            @truncate(@as(u32, @bitCast(t1)) >> 16),
+            @truncate(@as(u32, @bitCast(t1)) >> 24),
+            @truncate(@as(u32, @bitCast(t2)) >> 0),
+            @truncate(@as(u32, @bitCast(t2)) >> 8),
+            @truncate(@as(u32, @bitCast(t2)) >> 16),
+            @truncate(@as(u32, @bitCast(t2)) >> 24),
+        };
+        return std.hash.Wyhash.hash(0, &bytes);
+    }
+
+    /// Hash single token for bigram key
+    fn hashBigram(t: Token) u64 {
+        const bytes = [_]u8{
+            @truncate(@as(u32, @bitCast(t)) >> 0),
+            @truncate(@as(u32, @bitCast(t)) >> 8),
+            @truncate(@as(u32, @bitCast(t)) >> 16),
+            @truncate(@as(u32, @bitCast(t)) >> 24),
+        };
+        return std.hash.Wyhash.hash(0, &bytes);
+    }
+
+    /// Record a token sequence to build n-gram statistics
+    pub fn recordSequence(self: *Self, tokens: []const Token) !void {
+        const now = std.time.timestamp();
+
+        // Record trigrams
+        if (tokens.len >= 3) {
+            var i: usize = 2;
+            while (i < tokens.len) : (i += 1) {
+                const key = hashTrigram(tokens[i - 2], tokens[i - 1]);
+                const next_token = tokens[i];
+
+                if (self.trigrams.getPtr(key)) |dist| {
+                    // Update existing distribution
+                    dist.total_count += 1;
+                    if (next_token == dist.top_token) {
+                        dist.count += 1;
+                    } else if (dist.count < dist.total_count / 2) {
+                        // New token is more frequent, replace
+                        dist.top_token = next_token;
+                        dist.count = 1;
+                    }
+                    dist.last_seen = now;
+                } else {
+                    // New trigram
+                    try self.trigrams.put(key, TokenDistribution{
+                        .top_token = next_token,
+                        .count = 1,
+                        .total_count = 1,
+                        .last_seen = now,
+                    });
+                    self.total_trigrams += 1;
+                }
+            }
+        }
+
+        // Record bigrams
+        if (tokens.len >= 2) {
+            var i: usize = 1;
+            while (i < tokens.len) : (i += 1) {
+                const key = hashBigram(tokens[i - 1]);
+                const next_token = tokens[i];
+
+                if (self.bigrams.getPtr(key)) |dist| {
+                    dist.total_count += 1;
+                    if (next_token == dist.top_token) {
+                        dist.count += 1;
+                    } else if (dist.count < dist.total_count / 2) {
+                        dist.top_token = next_token;
+                        dist.count = 1;
+                    }
+                    dist.last_seen = now;
+                } else {
+                    try self.bigrams.put(key, TokenDistribution{
+                        .top_token = next_token,
+                        .count = 1,
+                        .total_count = 1,
+                        .last_seen = now,
+                    });
+                    self.total_bigrams += 1;
+                }
+            }
+        }
+    }
+
+    /// Draft next tokens based on context
+    /// Returns slice of predicted tokens (may be empty if no confident prediction)
+    pub fn draft(
+        self: *Self,
+        context: []const Token,
+        output: []Token,
+    ) []Token {
+        if (context.len < 2) {
+            self.cache_misses += 1;
+            return output[0..0];
+        }
+
+        var drafted: usize = 0;
+        var ctx_t1 = context[context.len - 2];
+        var ctx_t2 = context[context.len - 1];
+
+        while (drafted < output.len and drafted < self.max_draft_tokens) {
+            // Try trigram first
+            const trigram_key = hashTrigram(ctx_t1, ctx_t2);
+            if (self.trigrams.get(trigram_key)) |dist| {
+                if (dist.probability() >= self.min_confidence) {
+                    output[drafted] = dist.top_token;
+                    drafted += 1;
+                    ctx_t1 = ctx_t2;
+                    ctx_t2 = dist.top_token;
+                    self.cache_hits += 1;
+                    continue;
+                }
+            }
+
+            // Fallback to bigram
+            const bigram_key = hashBigram(ctx_t2);
+            if (self.bigrams.get(bigram_key)) |dist| {
+                if (dist.probability() >= self.min_confidence * 0.8) { // Lower threshold for bigrams
+                    output[drafted] = dist.top_token;
+                    drafted += 1;
+                    ctx_t1 = ctx_t2;
+                    ctx_t2 = dist.top_token;
+                    self.cache_hits += 1;
+                    continue;
+                }
+            }
+
+            // No confident prediction
+            self.cache_misses += 1;
+            break;
+        }
+
+        return output[0..drafted];
+    }
+
+    /// Verify drafted tokens against actual model output
+    /// Returns number of tokens that matched (accepted)
+    pub fn verify(
+        self: *Self,
+        drafts: []const Token,
+        actual: []const Token,
+    ) usize {
+        _ = self;
+        var accepted: usize = 0;
+        const check_len = @min(drafts.len, actual.len);
+
+        while (accepted < check_len) : (accepted += 1) {
+            if (drafts[accepted] != actual[accepted]) {
+                break;
+            }
+        }
+
+        return accepted;
+    }
+
+    /// Save cache to file for persistence
+    pub fn save(self: *Self, path: []const u8) !void {
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        var writer = file.writer();
+
+        // Write header
+        try writer.writeAll("ZELL_NGRAM_V1\n");
+
+        // Write trigrams
+        try writer.print("TRIGRAMS {d}\n", .{self.trigrams.count()});
+        var tri_iter = self.trigrams.iterator();
+        while (tri_iter.next()) |entry| {
+            try writer.print("{x} {d} {d} {d} {d}\n", .{
+                entry.key_ptr.*,
+                @as(u32, @bitCast(entry.value_ptr.top_token)),
+                entry.value_ptr.count,
+                entry.value_ptr.total_count,
+                entry.value_ptr.last_seen,
+            });
+        }
+
+        // Write bigrams
+        try writer.print("BIGRAMS {d}\n", .{self.bigrams.count()});
+        var bi_iter = self.bigrams.iterator();
+        while (bi_iter.next()) |entry| {
+            try writer.print("{x} {d} {d} {d} {d}\n", .{
+                entry.key_ptr.*,
+                @as(u32, @bitCast(entry.value_ptr.top_token)),
+                entry.value_ptr.count,
+                entry.value_ptr.total_count,
+                entry.value_ptr.last_seen,
+            });
+        }
+
+        logger.info("Saved n-gram cache: {d} trigrams, {d} bigrams", .{
+            self.trigrams.count(),
+            self.bigrams.count(),
+        });
+    }
+
+    /// Load cache from file
+    pub fn load(allocator: std.mem.Allocator, path: []const u8) !Self {
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+
+        var self = Self.init(allocator);
+        errdefer self.deinit();
+
+        var reader = file.reader();
+        var buf: [1024]u8 = undefined;
+
+        // Verify header
+        const header = reader.readUntilDelimiter(&buf, '\n') catch return self;
+        if (!std.mem.eql(u8, header, "ZELL_NGRAM_V1")) {
+            return error.InvalidCacheFormat;
+        }
+
+        // Read trigrams section
+        const tri_header = reader.readUntilDelimiter(&buf, '\n') catch return self;
+        if (std.mem.startsWith(u8, tri_header, "TRIGRAMS ")) {
+            const count_str = tri_header["TRIGRAMS ".len..];
+            const count = std.fmt.parseInt(usize, count_str, 10) catch 0;
+            _ = count;
+
+            while (reader.readUntilDelimiter(&buf, '\n')) |line| {
+                if (std.mem.startsWith(u8, line, "BIGRAMS ")) break;
+
