+                const top_token: Token = @bitCast(std.fmt.parseInt(u32, parts.next() orelse continue, 10) catch continue);
+                const cnt = std.fmt.parseInt(u32, parts.next() orelse continue, 10) catch continue;
+                const total = std.fmt.parseInt(u32, parts.next() orelse continue, 10) catch continue;
+                const last_seen = std.fmt.parseInt(i64, parts.next() orelse continue, 10) catch continue;
+
+                try self.trigrams.put(key, TokenDistribution{
+                    .top_token = top_token,
+                    .count = cnt,
+                    .total_count = total,
+                    .last_seen = last_seen,
+                });
+            } else |_| {}
+        }
+
+        // Read bigrams (similar parsing)
+        while (reader.readUntilDelimiter(&buf, '\n')) |line| {
+            var parts = std.mem.tokenizeScalar(u8, line, ' ');
+            const key = std.fmt.parseInt(u64, parts.next() orelse continue, 16) catch continue;
+            const top_token: Token = @bitCast(std.fmt.parseInt(u32, parts.next() orelse continue, 10) catch continue);
+            const cnt = std.fmt.parseInt(u32, parts.next() orelse continue, 10) catch continue;
+            const total = std.fmt.parseInt(u32, parts.next() orelse continue, 10) catch continue;
+            const last_seen = std.fmt.parseInt(i64, parts.next() orelse continue, 10) catch continue;
