+            try self.bigrams.put(key, TokenDistribution{
+                .top_token = top_token,
+                .count = cnt,
+                .total_count = total,
+                .last_seen = last_seen,
+            });
+        } else |_| {}
+
+        self.total_trigrams = self.trigrams.count();
+        self.total_bigrams = self.bigrams.count();
+
+        logger.info("Loaded n-gram cache: {d} trigrams, {d} bigrams", .{
+            self.total_trigrams,
+            self.total_bigrams,
+        });
+
+        return self;
+    }
+
+    /// Get cache statistics
+    pub fn getStats(self: *const Self) struct {
+        trigram_count: usize,
+        bigram_count: usize,
+        cache_hits: usize,
+        cache_misses: usize,
+        hit_rate: f32,
+    } {
+        const total = self.cache_hits + self.cache_misses;
+        return .{
+            .trigram_count = self.total_trigrams,
+            .bigram_count = self.total_bigrams,
+            .cache_hits = self.cache_hits,
+            .cache_misses = self.cache_misses,
+            .hit_rate = if (total > 0) @as(f32, @floatFromInt(self.cache_hits)) / @as(f32, @floatFromInt(total)) else 0.0,
+        };
+    }
+
+    /// Prune old entries to keep cache size manageable
+    pub fn prune(self: *Self, max_age_days: i64) void {
+        const now = std.time.timestamp();
+        const max_age_seconds = max_age_days * 24 * 60 * 60;
+
+        var keys_to_remove = std.ArrayList(u64).init(self.allocator);
+        defer keys_to_remove.deinit();
+
