+        var tri_iter = self.trigrams.iterator();
+        while (tri_iter.next()) |entry| {
+            if (now - entry.value_ptr.last_seen > max_age_seconds) {
+                keys_to_remove.append(entry.key_ptr.*) catch continue;
+            }
+        }
