+        for (keys_to_remove.items) |key| {
+            _ = self.bigrams.remove(key);
+        }
+
+        self.total_trigrams = self.trigrams.count();
+        self.total_bigrams = self.bigrams.count();
+
+        logger.info("Pruned n-gram cache: removed {d} trigrams, {d} bigrams", .{
+            removed_trigrams,
+            keys_to_remove.items.len,
+        });
+    }
+};
+
+// Tests
+test "ngram cache basic operations" {
+    const allocator = std.testing.allocator;
