+const std = @import("std");
+
+/// SIMD-accelerated quantization utilities using Zig's @Vector
+///
+/// These routines provide high-performance dequantization for Q4/Q8 formats,
+/// optimized for CPU inference paths and sampler computations.
+
+// =============================================================================
+// SIMD Vector Types
+// =============================================================================
+
+/// 32-wide SIMD vector for processing quantized weights
+pub const Vec32f = @Vector(32, f32);
+pub const Vec16f = @Vector(16, f32);
+pub const Vec8f = @Vector(8, f32);
+
+/// Integer vectors for unpacking
+pub const Vec32i8 = @Vector(32, i8);
+pub const Vec32u8 = @Vector(32, u8);
+pub const Vec16i16 = @Vector(16, i16);
+
+// =============================================================================
+// Quantization Block Formats
+// =============================================================================
+
+/// Q4_0 block: 32 weights packed into 16 bytes + 2-byte scale
+/// Total: 18 bytes per 32 weights = 4.5 bits per weight
+pub const Q4_0Block = extern struct {
+    d: f16, // delta (scale factor)
+    qs: [16]u8, // quantized values (nibbles)
+};
+
+/// Q8_0 block: 32 weights as 8-bit integers + 2-byte scale
+/// Total: 34 bytes per 32 weights = 8.5 bits per weight
+pub const Q8_0Block = extern struct {
+    d: f16, // delta (scale factor)
+    qs: [32]i8, // quantized values
+};
+
+// =============================================================================
+// Q4_0 Dequantization (4-bit)
+// =============================================================================
+
+/// Dequantize a Q4_0 block to 32 floats using SIMD
+/// Q4_0 format: 4-bit signed integers (-8 to 7) scaled by d
+pub fn dequantizeQ4_0(block: *const Q4_0Block) Vec32f {
+    const scale: f32 = @floatCast(block.d);
+
+    // Unpack 16 bytes into 32 nibbles
+    var values: [32]i8 = undefined;
+    for (0..16) |i| {
+        // Low nibble: bits 0-3, bias by -8 to get signed
+        values[i * 2 + 0] = @as(i8, @intCast(block.qs[i] & 0x0F)) - 8;
+        // High nibble: bits 4-7, bias by -8
+        values[i * 2 + 1] = @as(i8, @intCast(block.qs[i] >> 4)) - 8;
+    }
+
+    // Convert to float vector and scale
+    const vec_i8: Vec32i8 = values;
+    const vec_f32: Vec32f = @floatFromInt(vec_i8);
+
+    return vec_f32 * @as(Vec32f, @splat(scale));
+}
+
+/// Batch dequantize multiple Q4_0 blocks
+pub fn dequantizeQ4_0Batch(blocks: []const Q4_0Block, output: []f32) void {
+    std.debug.assert(output.len >= blocks.len * 32);
+
+    for (blocks, 0..) |*block, i| {
+        const result = dequantizeQ4_0(block);
+        const dst: *[32]f32 = @ptrCast(output[i * 32 ..].ptr);
+        dst.* = result;
+    }
+}
+
+// =============================================================================
+// Q8_0 Dequantization (8-bit)
+// =============================================================================
+
+/// Dequantize a Q8_0 block to 32 floats using SIMD
+pub fn dequantizeQ8_0(block: *const Q8_0Block) Vec32f {
+    const scale: f32 = @floatCast(block.d);
+
+    // Direct conversion from i8 to f32
+    const vec_i8: Vec32i8 = block.qs;
+    const vec_f32: Vec32f = @floatFromInt(vec_i8);
+
+    return vec_f32 * @as(Vec32f, @splat(scale));
+}
+
+/// Batch dequantize multiple Q8_0 blocks
+pub fn dequantizeQ8_0Batch(blocks: []const Q8_0Block, output: []f32) void {
+    std.debug.assert(output.len >= blocks.len * 32);
+
+    for (blocks, 0..) |*block, i| {
+        const result = dequantizeQ8_0(block);
+        const dst: *[32]f32 = @ptrCast(output[i * 32 ..].ptr);
+        dst.* = result;
+    }
+}
+
+// =============================================================================
+// SIMD Math Operations
+// =============================================================================
+
+/// SIMD dot product of two f32 arrays
+/// Processes 32 elements at a time for maximum throughput
+pub fn simdDotProduct(a: []const f32, b: []const f32) f32 {
+    std.debug.assert(a.len == b.len);
+
+    var sum: Vec32f = @splat(0.0);
+    var i: usize = 0;
+
+    // Process 32 elements at a time
+    while (i + 32 <= a.len) : (i += 32) {
+        const va: Vec32f = a[i..][0..32].*;
+        const vb: Vec32f = b[i..][0..32].*;
+        sum += va * vb;
+    }
+
+    // Horizontal sum of SIMD vector
+    var result = @reduce(.Add, sum);
+
+    // Handle remaining elements (scalar)
+    while (i < a.len) : (i += 1) {
+        result += a[i] * b[i];
+    }
+
+    return result;
+}
+
+/// SIMD vector addition: c = a + b
+pub fn simdAdd(a: []const f32, b: []const f32, c: []f32) void {
+    std.debug.assert(a.len == b.len and b.len == c.len);
+
+    var i: usize = 0;
+    while (i + 32 <= a.len) : (i += 32) {
+        const va: Vec32f = a[i..][0..32].*;
+        const vb: Vec32f = b[i..][0..32].*;
+        const dst: *[32]f32 = @ptrCast(c[i..].ptr);
+        dst.* = va + vb;
+    }
+
+    // Scalar fallback for remainder
+    while (i < a.len) : (i += 1) {
+        c[i] = a[i] + b[i];
+    }
+}
+
+/// SIMD scalar multiply: c = a * scalar
+pub fn simdScale(a: []const f32, scalar: f32, c: []f32) void {
+    std.debug.assert(a.len == c.len);
+
+    const scale_vec: Vec32f = @splat(scalar);
+    var i: usize = 0;
+
+    while (i + 32 <= a.len) : (i += 32) {
+        const va: Vec32f = a[i..][0..32].*;
+        const dst: *[32]f32 = @ptrCast(c[i..].ptr);
+        dst.* = va * scale_vec;
+    }
+
+    while (i < a.len) : (i += 1) {
+        c[i] = a[i] * scalar;
+    }
+}
+
+/// SIMD softmax (for sampler acceleration)
+/// Returns max value for numerical stability
+pub fn simdSoftmax(logits: []f32) f32 {
+    // Find max for numerical stability
+    var max_vec: Vec32f = @splat(-std.math.inf(f32));
+    var i: usize = 0;
+
+    while (i + 32 <= logits.len) : (i += 32) {
+        const v: Vec32f = logits[i..][0..32].*;
+        max_vec = @max(max_vec, v);
+    }
+
+    var max_val = @reduce(.Max, max_vec);
+    while (i < logits.len) : (i += 1) {
+        max_val = @max(max_val, logits[i]);
+    }
+
+    // Compute exp(x - max) and sum
+    var sum_vec: Vec32f = @splat(0.0);
+    const max_splat: Vec32f = @splat(max_val);
+    i = 0;
+
+    while (i + 32 <= logits.len) : (i += 32) {
+        const v: Vec32f = logits[i..][0..32].*;
+        const shifted = v - max_splat;
+        const exp_v = @exp(shifted);
+        sum_vec += exp_v;
+
+        // Store exp values
+        const dst: *[32]f32 = @ptrCast(logits[i..].ptr);
+        dst.* = exp_v;
+    }
+
+    var sum = @reduce(.Add, sum_vec);
+    while (i < logits.len) : (i += 1) {
+        const exp_v = @exp(logits[i] - max_val);
+        sum += exp_v;
+        logits[i] = exp_v;
+    }
+
+    // Normalize
+    const inv_sum: Vec32f = @splat(1.0 / sum);
+    i = 0;
+
+    while (i + 32 <= logits.len) : (i += 32) {
+        const v: Vec32f = logits[i..][0..32].*;
+        const dst: *[32]f32 = @ptrCast(logits[i..].ptr);
+        dst.* = v * inv_sum;
+    }
+
+    const inv_sum_scalar = 1.0 / sum;
+    while (i < logits.len) : (i += 1) {
+        logits[i] *= inv_sum_scalar;
+    }
+
+    return max_val;
+}
+
+/// Compute entropy of a probability distribution (for token pruning)
+pub fn simdEntropy(probs: []const f32) f32 {
+    var entropy_vec: Vec32f = @splat(0.0);
+    const eps: Vec32f = @splat(1e-10);
+    var i: usize = 0;
+
+    while (i + 32 <= probs.len) : (i += 32) {
+        const p: Vec32f = probs[i..][0..32].*;
+        const p_safe = @max(p, eps);
+        const log_p = @log(p_safe);
+        entropy_vec -= p * log_p;
+    }
+
+    var entropy = @reduce(.Add, entropy_vec);
+
+    while (i < probs.len) : (i += 1) {
+        const p = @max(probs[i], 1e-10);
+        entropy -= p * @log(p);
+    }
+
+    return entropy;
+}
